import React from 'react';
import styles from '../../css/dashboard.module.css'; 
import ToDoBlock from './ToDoBlock';
import TaskStatusBlock from './TaskStatusBlock';
import CompletedTaskBlock from './CompletedTaskBlock';

const DashboardContent = () => {
    return (
        <div className={styles.dashboard}>
            <div className={styles.top_part}>
                <label className={styles.welcome_back}>Welcome back, Sundar</label>
                <img src="../images/hand wave.png" alt="hand wave" className={styles.hand_wave} />
                
                <div className={styles.img_list}>
                    <img src="../images/list_img1.png" alt="list img" />
                    <img src="../images/list_img2.png" alt="list img" />
                    <img src="../images/list_img3.png" alt="list img" />
                    <img src="../images/list_img4.png" alt="list img" />
                    <img src="../images/list_img4.png" alt="list img" />
                </div>
                
                <button className={styles.invite_button}>
                    <img src="../images/icons/invite.svg" alt="invite" />Invite
                </button>
            </div>

            <div className={styles.dashboard_content}>
                
                <ToDoBlock />

                <TaskStatusBlock />

                {/* Completed Task Block */}

            </div>
        </div>
    );
};

export default DashboardContent;
